17	// runRecord is the on-disk JSON format for a FEAT-010 run file.
18	type runRecord struct {
19		ID          string   `json:"id"`
20		Layer       string   `json:"layer"`
21		Status      string   `json:"status"`
22		StartedAt   string   `json:"started_at,omitempty"`
23		CompletedAt string   `json:"completed_at,omitempty"`
24		BeadID      string   `json:"bead_id,omitempty"`
25		ArtifactID  string   `json:"artifact_id,omitempty"`
26		ParentRunID string   `json:"parent_run_id,omitempty"`
27		ChildRunIDs []string `json:"child_run_ids,omitempty"`
28	
29		// Work-layer fields
30		QueueInputs     json.RawMessage `json:"queue_inputs,omitempty"`
31		StopCondition   string          `json:"stop_condition,omitempty"`
32		SelectedBeadIDs []string        `json:"selected_bead_ids,omitempty"`
33	
34		// Try-layer fields
35		BaseRevision   string          `json:"base_revision,omitempty"`
36		ResultRevision string          `json:"result_revision,omitempty"`
37		WorktreePath   string          `json:"worktree_path,omitempty"`
38		MergeOutcome   string          `json:"merge_outcome,omitempty"`
39		CheckResults   json.RawMessage `json:"check_results,omitempty"`
40	
41		// Run-layer fields
42		PromptSummary string   `json:"prompt_summary,omitempty"`
43		PowerMin      int      `json:"power_min,omitempty"`
44		PowerMax      int      `json:"power_max,omitempty"`
45		Harness       string   `json:"harness,omitempty"`
46		Provider      string   `json:"provider,omitempty"`
47		Model         string   `json:"model,omitempty"`
48		TokensIn      int      `json:"tokens_in,omitempty"`
49		TokensOut     int      `json:"tokens_out,omitempty"`
50		CostUSD       float64  `json:"cost_usd,omitempty"`
51		DurationMs    int      `json:"duration_ms,omitempty"`
52		OutputExcerpt string   `json:"output_excerpt,omitempty"`
53		EvidenceLinks []string `json:"evidence_links,omitempty"`
54	}
