56	// runRecordToGQL converts a runRecord to the GraphQL Run type.
57	func runRecordToGQL(rec runRecord) *ddxgraphql.Run {
58		layer := ddxgraphql.RunLayerRun
59		switch strings.ToLower(rec.Layer) {
60		case "work":
61			layer = ddxgraphql.RunLayerWork
62		case "try":
63			layer = ddxgraphql.RunLayerTry
64		}
65	
66		run := &ddxgraphql.Run{
67			ID:          rec.ID,
68			Layer:       layer,
69			Status:      rec.Status,
70			ChildRunIds: rec.ChildRunIDs,
71		}
72		if run.ChildRunIds == nil {
73			run.ChildRunIds = []string{}
74		}
75		if rec.StartedAt != "" {
76			s := normalizeISOTime(rec.StartedAt)
77			run.StartedAt = &s
78		}
79		if rec.CompletedAt != "" {
80			s := normalizeISOTime(rec.CompletedAt)
81			run.CompletedAt = &s
82		}
83		if rec.BeadID != "" {
84			run.BeadID = &rec.BeadID
85		}
86		if rec.ArtifactID != "" {
87			run.ArtifactID = &rec.ArtifactID
88		}
89		if rec.ParentRunID != "" {
90			run.ParentRunID = &rec.ParentRunID
91		}
92	
93		switch layer {
94		case ddxgraphql.RunLayerWork:
95			if len(rec.QueueInputs) > 0 {
96				s := string(rec.QueueInputs)
97				run.QueueInputs = &s
98			}
99			if rec.StopCondition != "" {
100				run.StopCondition = &rec.StopCondition
101			}
102			if len(rec.SelectedBeadIDs) > 0 {
103				run.SelectedBeadIds = rec.SelectedBeadIDs
104			}
105		case ddxgraphql.RunLayerTry:
106			if rec.BaseRevision != "" {
107				run.BaseRevision = &rec.BaseRevision
108			}
109			if rec.ResultRevision != "" {
110				run.ResultRevision = &rec.ResultRevision
111			}
112			if rec.WorktreePath != "" {
113				run.WorktreePath = &rec.WorktreePath
114			}
115			if rec.MergeOutcome != "" {
116				run.MergeOutcome = &rec.MergeOutcome
117			}
118			if len(rec.CheckResults) > 0 {
119				s := string(rec.CheckResults)
120				run.CheckResults = &s
121			}
122		case ddxgraphql.RunLayerRun:
123			if rec.PromptSummary != "" {
124				run.PromptSummary = &rec.PromptSummary
125			}
126			if rec.PowerMin > 0 {
127				run.PowerMin = &rec.PowerMin
128			}
129			if rec.PowerMax > 0 {
130				run.PowerMax = &rec.PowerMax
131			}
132			if rec.Harness != "" {
133				run.Harness = &rec.Harness
134			}
135			if rec.Provider != "" {
136				run.Provider = &rec.Provider
137			}
138			if rec.Model != "" {
139				run.Model = &rec.Model
140			}
141			if rec.TokensIn > 0 {
142				run.TokensIn = &rec.TokensIn
143			}
144			if rec.TokensOut > 0 {
145				run.TokensOut = &rec.TokensOut
146			}
147			if rec.CostUSD != 0 {
148				run.CostUsd = &rec.CostUSD
149			}
150			if rec.DurationMs > 0 {
151				run.DurationMs = &rec.DurationMs
152			}
153			if rec.OutputExcerpt != "" {
154				run.OutputExcerpt = &rec.OutputExcerpt
155			}
156			if len(rec.EvidenceLinks) > 0 {
157				run.EvidenceLinks = rec.EvidenceLinks
158			}
159		}
160		return run
161	}
