163	// scanRunStore reads FEAT-010 run JSON files from .ddx/exec/runs/.
164	func scanRunStore(projectRoot string) []*ddxgraphql.Run {
165		dir := filepath.Join(projectRoot, runStoreDir)
166		entries, err := os.ReadDir(dir)
167		if err != nil {
168			return nil
169		}
170		out := make([]*ddxgraphql.Run, 0, len(entries))
171		for _, entry := range entries {
172			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
173				continue
174			}
175			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
176			if err != nil {
177				continue
178			}
179			var rec runRecord
180			if err := json.Unmarshal(data, &rec); err != nil || rec.ID == "" {
181				continue
182			}
183			out = append(out, runRecordToGQL(rec))
184		}
185		return out
186	}
