188	// synthesizeRunsFromBundles derives run-layer Run records from .ddx/executions/
189	// bundle directories. Each bundle = one `run`-layer agent invocation.
190	func synthesizeRunsFromBundles(projectID, projectRoot string) []*ddxgraphql.Run {
191		dir := filepath.Join(projectRoot, agent.ExecuteBeadArtifactDir)
192		entries, err := os.ReadDir(dir)
193		if err != nil {
194			return nil
195		}
196		out := make([]*ddxgraphql.Run, 0, len(entries))
197		for _, entry := range entries {
198			if !entry.IsDir() {
199				continue
200			}
201			name := entry.Name()
202			if !looksLikeBundleID(name) {
203				continue
204			}
205			bundleDirAbs := filepath.Join(dir, name)
206			exec := loadExecutionBundle(projectID, projectRoot, bundleDirAbs, name)
207			if exec == nil {
208				continue
209			}
210			run := executionBundleToRun(name, exec)
211			out = append(out, run)
212		}
213		sort.Slice(out, func(i, j int) bool {
214			si, sj := "", ""
215			if out[i].StartedAt != nil {
216				si = *out[i].StartedAt
217			}
218			if out[j].StartedAt != nil {
219				sj = *out[j].StartedAt
220			}
221			return si > sj
222		})
223		return out
224	}
