226	// executionBundleToRun converts an Execution bundle to a run-layer Run record.
227	func executionBundleToRun(id string, exec *ddxgraphql.Execution) *ddxgraphql.Run {
228		status := "success"
229		if exec.Status != nil {
230			status = *exec.Status
231		} else if exec.Verdict != nil {
232			status = strings.ToLower(*exec.Verdict)
233		}
234	
235		run := &ddxgraphql.Run{
236			ID:          "exec-" + id,
237			Layer:       ddxgraphql.RunLayerRun,
238			Status:      status,
239			ChildRunIds: []string{},
240		}
241		if exec.StartedAt != nil {
242			run.StartedAt = exec.StartedAt
243		} else {
244			// Fall back to createdAt
245			s := exec.CreatedAt
246			run.StartedAt = &s
247		}
248		if exec.FinishedAt != nil {
249			run.CompletedAt = exec.FinishedAt
250		}
251		if exec.BeadID != nil {
252			run.BeadID = exec.BeadID
253		}
254		if exec.Harness != nil {
255			run.Harness = exec.Harness
256		}
257		if exec.Model != nil {
258			run.Model = exec.Model
259		}
260		if exec.DurationMs != nil {
261			run.DurationMs = exec.DurationMs
262		}
263		if exec.CostUsd != nil {
264			run.CostUsd = exec.CostUsd
265		}
266		if exec.Tokens != nil {
267			t := *exec.Tokens
268			run.TokensIn = &t
269		}
270		run.EvidenceLinks = []string{exec.BundlePath}
271		return run
272	}
