274	// GetRunsGraphQL implements RunsStateProvider.
275	func (s *ServerState) GetRunsGraphQL(projectID string, filter ddxgraphql.RunFilter) []*ddxgraphql.Run {
276		var all []*ddxgraphql.Run
277	
278		if projectID != "" {
279			proj, ok := s.GetProjectByID(projectID)
280			if !ok {
281				return nil
282			}
283			all = s.loadRunsForProject(projectID, proj.Path)
284		} else {
285			for _, proj := range s.GetProjects(false) {
286				all = append(all, s.loadRunsForProject(proj.ID, proj.Path)...)
287			}
288			sort.Slice(all, func(i, j int) bool {
289				si, sj := "", ""
290				if all[i].StartedAt != nil {
291					si = *all[i].StartedAt
292				}
293				if all[j].StartedAt != nil {
294					sj = *all[j].StartedAt
295				}
296				return si > sj
297			})
298		}
299		return ddxgraphql.ApplyRunFilter(all, filter)
300	}
