302	// tagProjectID sets ProjectID on each run in-place.
303	func tagProjectID(runs []*ddxgraphql.Run, projectID string) []*ddxgraphql.Run {
304		for _, r := range runs {
305			pid := projectID
306			r.ProjectID = &pid
307		}
308		return runs
309	}
310	
311	// loadRunsForProject loads runs for a single project, merging the file store
312	// with synthesized execution bundle records.
313	func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
314		// Primary: FEAT-010 run store
315		stored := scanRunStore(projectRoot)
316	
317		// Secondary: synthesize run-layer records from .ddx/executions/ bundles,
318		// but only include IDs that are not already in the stored set.
319		storedIDs := make(map[string]bool, len(stored))
320		for _, r := range stored {
321			storedIDs[r.ID] = true
322		}
323	
324		synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
325		for _, r := range synthesized {
326			if !storedIDs[r.ID] {
327				stored = append(stored, r)
328			}
329		}
330	
331		// Sort newest-first by startedAt.
332		sort.Slice(stored, func(i, j int) bool {
333			si, sj := "", ""
334			if stored[i].StartedAt != nil {
335				si = *stored[i].StartedAt
336			}
337			if stored[j].StartedAt != nil {
338				sj = *stored[j].StartedAt
339			}
340			return si > sj
341		})
342		return tagProjectID(stored, projectID)
343	}
344	
345	// GetRunGraphQL implements RunsStateProvider.
346	func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
347		if id == "" {
348			return nil, false
349		}
350		// Search all projects.
351		for _, proj := range s.GetProjects(false) {
352			runs := s.loadRunsForProject(proj.ID, proj.Path)
353			for _, r := range runs {
354				if r.ID == id {
355					return r, true
356				}
357			}
358		}
359		return nil, false
360	}
