631	// GetAgentSessionsGraphQL implements ddxgraphql.StateProvider.
632	// Reads pointer-only monthly session shards from every registered project.
633	func (s *ServerState) GetAgentSessionsGraphQL(startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
634		projects := s.GetProjects(false)
635		var out []*ddxgraphql.AgentSession
636		for _, proj := range projects {
637			sessions := readProjectSessions(proj, startedAfter, startedBefore)
638			out = append(out, sessions...)
639		}
640		// Newest first.
641		sort.Slice(out, func(i, j int) bool {
642			ti, _ := time.Parse(time.RFC3339, out[i].StartedAt)
643			tj, _ := time.Parse(time.RFC3339, out[j].StartedAt)
644			return ti.After(tj)
645		})
646		return out
647	}
