649	// GetAgentSessionGraphQL implements ddxgraphql.StateProvider.
650	func (s *ServerState) GetAgentSessionGraphQL(id string) (*ddxgraphql.AgentSession, bool) {
651		projects := s.GetProjects(false)
652		for _, proj := range projects {
653			logDir := agent.SessionLogDirForWorkDir(proj.Path)
654			entry, ok, err := agent.FindSessionIndex(logDir, id)
655			if err != nil || !ok {
656				continue
657			}
658			sess := agentSessionFromIndex(proj.ID, entry)
659			bodies := agent.LoadSessionBodies(proj.Path, entry)
660			if bodies.Prompt != "" {
661				sess.Prompt = &bodies.Prompt
662			}
663			if bodies.Response != "" {
664				sess.Response = &bodies.Response
665			}
666			if bodies.Stderr != "" {
667				sess.Stderr = &bodies.Stderr
668			}
669			return sess, true
670		}
671		return nil, false
672	}
