717	// readProjectSessions reads monthly session shards for one project and maps to graphql types.
718	func readProjectSessions(proj ProjectEntry, startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
719		logDir := agent.SessionLogDirForWorkDir(proj.Path)
720		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
721			StartedAfter:  startedAfter,
722			StartedBefore: startedBefore,
723			DefaultRecent: startedAfter == nil && startedBefore == nil,
724		})
725		if err != nil {
726			return nil
727		}
728		out := make([]*ddxgraphql.AgentSession, 0, len(entries))
729		for _, e := range entries {
730			sess := agentSessionFromIndex(proj.ID, e)
731			out = append(out, sess)
732		}
733		return out
734	}
