736	func localCostPer1KTokens(projectRoot string) *float64 {
737		cfg, err := config.LoadWithWorkingDir(projectRoot)
738		if err != nil || cfg.Cost == nil || cfg.Cost.LocalPer1KTokens == nil {
739			return nil
740		}
741		rate := *cfg.Cost.LocalPer1KTokens
742		return &rate
743	}
744	
745	func agentSessionFromIndex(projectID string, e agent.SessionIndexEntry) *ddxgraphql.AgentSession {
746		billingMode := e.BillingMode
747		if billingMode == "" {
748			billingMode = agent.BillingModeFor(e.Harness, e.Surface, e.BaseURL)
749		}
750		sess := &ddxgraphql.AgentSession{
751			ID:          e.ID,
752			ProjectID:   projectID,
753			Harness:     e.Harness,
754			Model:       e.Model,
755			Effort:      e.Effort,
756			DurationMs:  e.DurationMS,
757			StartedAt:   e.StartedAt.UTC().Format(time.RFC3339),
758			BillingMode: billingMode,
759		}
760	
761		// Derive status and outcome from exit code / error.
762		if e.ExitCode != 0 || e.Outcome == "failure" {
763			sess.Status = "failed"
764			outcome := "failure"
765			sess.Outcome = &outcome
766			if e.Detail != "" {
767				sess.Detail = &e.Detail
768			}
769		} else {
770			sess.Status = "completed"
771			outcome := "success"
772			sess.Outcome = &outcome
773		}
774	
775		// EndedAt = StartedAt + duration.
776		if !e.EndedAt.IsZero() {
777			endedAt := e.EndedAt.UTC().Format(time.RFC3339)
778			sess.EndedAt = &endedAt
779		} else if e.DurationMS > 0 {
780			endedAt := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
781			sess.EndedAt = &endedAt
782		}
783	
