193		// Agent-log path — prefer explicit pointer, else the conventional
194		// per-session file under .ddx/agent-logs/.
195		if result.AgentLogPath != "" {
196			s := filepath.ToSlash(result.AgentLogPath)
197			exec.AgentLogPath = &s
198		} else if result.SessionID != "" {
199			s := filepath.ToSlash(filepath.Join(".ddx/agent-logs", "agent-"+result.SessionID+".jsonl"))
200			exec.AgentLogPath = &s
201		}
202		return exec
203	}
